def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo (pip install pygmo) "
                          "or provide a fallback. Original error: " + str(e))

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D).")
    N, D = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have same dimensionality as points (length D).")

    # If no points, return empty array of shape (0, D) or padded to k by repeats
    if N == 0:
        return np.empty((0, D))

    # Optional preprocessing: remove exact duplicate rows (keep first occurrence),
    # while remembering mapping so we can sample to reach k if needed.
    unique_points, inv_idx = np.unique(points, axis=0, return_inverse=True)
    points = unique_points
    N = points.shape[0]

    # If k <= 0 return empty
    if k <= 0:
        return np.empty((0, D))

    # If N == 0 (shouldn't happen after unique), return
    if N == 0:
        return np.empty((0, D))

    # If N <= k, return all points and pad (with random choices) to get exactly k rows
    if N <= k:
        if N == k:
            return points.copy()
        # need to pad: sample with replacement from available points
        need = k - N
        if N == 0:
            return np.empty((0, D))
        extra_idx = np.random.choice(np.arange(N), size=need, replace=True)
        return np.vstack([points, points[extra_idx]])

    # Greedy selection by marginal hypervolume contribution
    selected_mask = np.zeros(N, dtype=bool)
    current_hv = 0.0

    # helper to compute hypervolume of a set of indices
    def hv_of_indices(idx_array):
        if len(idx_array) == 0:
            return 0.0
        data = points[idx_array, :]
        hv = pg.hypervolume(data)
        return float(hv.compute(reference_point))

    # Precompute hv for singletons could help a bit, but we'll compute marginal contributions each round
    for _ in range(k):
        best_idx = None
        best_contrib = -np.inf

        # candidate indices (not yet selected)
        candidates = np.where(~selected_mask)[0]
        # For each candidate compute contribution = hv(selected ∪ {cand}) - current_hv
        # We can speed up slightly by skipping candidates that are identical to already selected ones (not likely here)
        for idx in candidates:
            # build indices of union
            if np.any(selected_mask):
                union_idx = np.nonzero(selected_mask)[0].tolist()
                union_idx.append(int(idx))
                hv_union = hv_of_indices(union_idx)
            else:
                hv_union = hv_of_indices([idx])
            contrib = hv_union - current_hv
            # numerical tolerance: clip tiny negatives to zero
            if contrib < 0 and contrib > -1e-12:
                contrib = 0.0
            # choose best; tie-break randomly among equals
            if contrib > best_contrib + 1e-12:
                best_contrib = contrib
                best_idx = int(idx)
            elif abs(contrib - best_contrib) <= 1e-12:
                # tie-break: choose randomly between current best and this idx
                if np.random.rand() < 0.5:
                    best_idx = int(idx)

        # If no positive contribution found (all zero), pick one remaining at random
        if best_idx is None:
            remaining = np.where(~selected_mask)[0]
            best_idx = int(np.random.choice(remaining))

        # Add best_idx to selection and update current_hv
        if not selected_mask[best_idx]:
            # compute new hv once
            if np.any(selected_mask):
                union_idx = np.nonzero(selected_mask)[0].tolist()
                union_idx.append(best_idx)
                new_hv = hv_of_indices(union_idx)
            else:
                new_hv = hv_of_indices([best_idx])
            current_hv = new_hv
            selected_mask[best_idx] = True
        else:
            # already selected (shouldn't happen) - break to avoid infinite loop
            break

    selected_points = points[selected_mask, :]

    # Ensure exactly k points (should be as N>k and loop runs k times), but guard defensively:
    if selected_points.shape[0] > k:
        selected_points = selected_points[:k]
    elif selected_points.shape[0] < k:
        # sample remaining from unselected (with replacement if insufficient)
        unselected = np.where(~selected_mask)[0]
        need = k - selected_points.shape[0]
        if len(unselected) == 0:
            # repeat some selected to reach k
            extra_idx = np.random.choice(np.arange(selected_points.shape[0]), size=need, replace=True)
            selected_points = np.vstack([selected_points, selected_points[extra_idx]])
        else:
            replace = len(unselected) < need
            pick = np.random.choice(unselected, size=need, replace=replace)
            selected_points = np.vstack([selected_points, points[pick]])

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    points = np.asarray(points, dtype=float)
    if points.ndim == 1:
        points = points.reshape(1, -1)
    N, D = points.shape

    if k <= 0:
        return np.empty((0, D), dtype=float)

    if N == 0:
        return np.empty((0, D), dtype=float)

    if reference_point is None:
        # ensure reference point strictly larger than all points (a bit of margin)
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError(f"reference_point must have shape ({D},), got {reference_point.shape}")

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computation. Install pygmo. Error: " + str(e))

    # If k >= N, return all points (if k > N, pad by sampling with replacement)
    if k >= N:
        if k == N:
            return points.copy()
        extra = k - N
        idx_extra = np.random.choice(N, size=extra, replace=True)
        return np.vstack([points, points[idx_extra]])

    # Helper: compute Pareto (non-dominated) mask for minimization problems
    def nondominated_mask(arr: np.ndarray) -> np.ndarray:
        n = arr.shape[0]
        if n == 0:
            return np.zeros(0, dtype=bool)
        mask = np.ones(n, dtype=bool)
        for i in range(n):
            if not mask[i]:
                continue
            # compare i with j>i to accelerate a bit
            for j in range(n):
                if i == j or not mask[j]:
                    continue
                # does j dominate i? (minimization)
                a = arr[j]
                b = arr[i]
                # j dominates i if all a <= b and any a < b
                if np.all(a <= b) and np.any(a < b):
                    mask[i] = False
                    break
                # also check if i dominates j to possibly mark j dominated
                if np.all(b <= a) and np.any(b < a):
                    mask[j] = False
        return mask

    # Quick per-point (single) hypervolume: product(reference - point) (>=0 if reference > point)
    # use max(..., 0.0) to guard against numerical negatives
    diffs = np.maximum(reference_point.reshape(1, -1) - points, 0.0)
    single_hv = np.prod(diffs, axis=1)

    # Candidate pruning: include all nondominated points plus top alpha*k by single_hv
    alpha = 5  # candidate multiplier; adjust for speed/quality tradeoff
    top_count = min(N, max(alpha * k, k + 5))
    top_indices = np.argsort(-single_hv)[:top_count]

    nd_mask = nondominated_mask(points)
    nd_indices = np.nonzero(nd_mask)[0]

    # combine candidates (preserve order: nondominated first, then top-by-single-hv)
    cand_set = []
    for idx in nd_indices:
        cand_set.append(idx)
    for idx in top_indices:
        if idx not in cand_set:
            cand_set.append(int(idx))
    candidates = cand_set  # list of indices

    # If candidates are fewer than k (rare), fall back to using top_by_single_hv to fill
    if len(candidates) < k:
        # ensure we have at least k candidates
        all_by_single = np.argsort(-single_hv)
        for idx in all_by_single:
            if int(idx) not in candidates:
                candidates.append(int(idx))
            if len(candidates) >= k:
                break

    # Greedy selection within candidate set: pick point with largest marginal HV each iteration
    selected_indices = []
    selected_set = set()
    current_pts = np.empty((0, D), dtype=float)
    current_hv = 0.0

    # To avoid repeated construction cost, we will use pg.hypervolume on stacked arrays as needed.
    for _ in range(k):
        best_idx = None
        best_gain = -np.inf
        # consider only candidates not yet selected
        for idx in candidates:
            if idx in selected_set:
                continue
            # quick bound: if current_pts empty, use precomputed single_hv
            if current_pts.shape[0] == 0:
                gain = single_hv[idx]
            else:
                # compute hv of current union candidate
                # assemble temporary array
                union = np.vstack([current_pts, points[idx].reshape(1, -1)])
                try:
                    gain = pg.hypervolume(union).compute(reference_point) - current_hv
                except Exception:
                    # fallback: if hypervolume fails for some reason, treat as no gain
                    gain = -np.inf
            # numerical tolerance
            if gain < 0 and gain > -1e-12:
                gain = 0.0
            if gain > best_gain:
                best_gain = gain
                best_idx = idx

        # If no candidate produced positive gain, pick remaining candidate with highest single_hv
        if best_idx is None:
            remaining_cands = [i for i in candidates if i not in selected_set]
            if not remaining_cands:
                break
            best_idx = max(remaining_cands, key=lambda i: single_hv[i])

        # accept choice
        selected_indices.append(best_idx)
        selected_set.add(best_idx)
        # update current_pts and current_hv
        if current_pts.shape[0] == 0:
            current_pts = points[best_idx].reshape(1, -1).copy()
            current_hv = single_hv[best_idx]
        else:
            current_pts = np.vstack([current_pts, points[best_idx].reshape(1, -1)])
            # recompute hv of current_pts
            current_hv = pg.hypervolume(current_pts).compute(reference_point)

    # If still fewer than k due to candidate exhaustion, fill from remaining by single_hv
    if len(selected_indices) < k:
        remaining_all = [i for i in range(N) if i not in selected_set]
        remaining_all_sorted = sorted(remaining_all, key=lambda i: -single_hv[i])
        for idx in remaining_all_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(idx)
            selected_set.add(idx)

    # Ensure exactly k items
    if len(selected_indices) > k:
        selected_indices = selected_indices[:k]

    subset = points[np.array(selected_indices)]
    return subset

