    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    from typing import Tuple, FrozenSet, Dict, List
    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations (pip install pygmo).") from e

    # Basic checks and conversions
    if not isinstance(points, np.ndarray):
        points = np.array(points)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D).")
    n, d = points.shape
    if k <= 0 or k > n:
        raise ValueError("k must be > 0 and <= number of points")

    # reference point
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.array(reference_point)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Hypervolume helper with caching
    hv_cache: Dict[FrozenSet[int], float] = {}

    def hv_of_indices(idxs: FrozenSet[int]) -> float:
        # idxs: frozenset of indices
        if not idxs:
            return 0.0
        if idxs in hv_cache:
            return hv_cache[idxs]
        arr = points[list(idxs)]
        try:
            hv = pg.hypervolume(arr)
            val = float(hv.compute(reference_point))
        except Exception:
            val = 0.0
        hv_cache[idxs] = val
        return val

    # If k equals n simply return all points
    if k == n:
        return points.copy()

    # Beam search parameters
    # Beam width grows modestly with k but bounded by n
    beam_width = int(max(5, min(50, 5 * k)))
    # Cap on total hypervolume evaluations to avoid explosion
    max_hv_evals = max(2000, 200 * k)  # tunable global cap

    hv_eval_count = 0

    # Initial beam: empty set with hv 0
    from collections import deque
    beams: List[Tuple[float, FrozenSet[int]]] = [(0.0, frozenset())]

    # Expand beam step by step until size k
    for size in range(k):
        candidates: Dict[FrozenSet[int], float] = {}  # mapping subset -> hv
        # For each current beam, try extending by all remaining points
        for hv_val, subset in beams:
            remaining = [i for i in range(n) if i not in subset]
            for idx in remaining:
                new_subset = frozenset(set(subset) | {idx})
                if new_subset in candidates:
                    continue  # already considered
                # compute hv
                new_hv = hv_of_indices(new_subset)
                hv_eval_count += 1
                candidates[new_subset] = new_hv
                # budget check
                if hv_eval_count >= max_hv_evals:
                    break
            if hv_eval_count >= max_hv_evals:
                break
        # If no candidates (shouldn't happen), break
        if not candidates:
            break
        # Select top beam_width subsets by hypervolume
        sorted_candidates = sorted(candidates.items(), key=lambda x: x[1], reverse=True)
        beams = [(hv, subset) for (subset, hv) in sorted_candidates[:beam_width]]
        # If hv budget exhausted, stop early
        if hv_eval_count >= max_hv_evals:
            break

    # Choose best beam (highest hv). If its size < k, we will greedily complete it.
    if beams:
        best_hv, best_subset = max(beams, key=lambda x: x[0])
    else:
        best_subset = frozenset()
        best_hv = 0.0

    # If best_subset is smaller than k (due to early stop), greedily add points maximizing marginal contribution
    current_subset = set(best_subset)
    # Precompute hv of current subset
    current_hv = hv_of_indices(frozenset(current_subset))
    # Greedy completion while keeping hv eval budget in check
    while len(current_subset) < k:
        best_gain = -np.inf
        best_idx = None
        for idx in range(n):
            if idx in current_subset:
                continue
            candidate_subset = frozenset(current_subset | {idx})
            # reuse cached if possible
            candidate_hv = hv_of_indices(candidate_subset)
            hv_eval_count += 1  # hv_of_indices may have returned cached value, but count conservatively
            gain = candidate_hv - current_hv
            if gain > best_gain:
                best_gain = gain
                best_idx = idx
            if hv_eval_count >= max_hv_evals:
                break
        # If no improvement or no index found (should not happen), fill arbitrarily
        if best_idx is None:
            for idx in range(n):
                if idx not in current_subset:
                    best_idx = idx
                    break
        current_subset.add(best_idx)
        current_hv = hv_of_indices(frozenset(current_subset))
        if hv_eval_count >= max_hv_evals:
            # If budget exhausted but still not full, fill with arbitrary remaining indices deterministically
            for idx in range(n):
                if len(current_subset) >= k:
                    break
                if idx not in current_subset:
                    current_subset.add(idx)
            break

    # Final selected indices
    selected_indices = sorted(list(current_subset))[:k]  # sorted for determinism
    selected_points = points[selected_indices]

    # safety check to ensure shape
    if selected_points.shape[0] != k:
        # pad/truncate deterministically
        sel = []
        chosen = set()
        for idx in selected_indices:
            if idx not in chosen:
                sel.append(points[idx])
                chosen.add(idx)
            if len(sel) == k:
                break
        if len(sel) < k:
            for idx in range(n):
                if idx not in chosen:
                    sel.append(points[idx])
                    chosen.add(idx)
                if len(sel) == k:
                    break
        selected_points = np.array(sel)

    return selected_points.reshape((k, d))

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError(
            "pygmo is required for hypervolume computations. "
            "Install it via `pip install pygmo` (or your platform's package manager)."
        ) from e

    points = np.asarray(points)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array with shape (N, D).")
    N, D = points.shape

    if not (isinstance(k, int) and k > 0):
        raise ValueError("k must be a positive integer.")
    if k > N:
        raise ValueError("k cannot be larger than the number of candidate points N.")

    # Default reference point: 10% larger than the per-dimension maxima
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError(f"reference_point must have shape ({D},)")

    # Optionally: filter dominated points (keeps only Pareto front) to reduce computations.
    # This is safe because dominated points never increase hypervolume beyond what non-dominated points can.
    def pareto_front_mask(pts):
        # returns boolean mask of nondominated points (True = nondominated)
        n = pts.shape[0]
        if n == 0:
            return np.zeros(0, dtype=bool)
        dominated = np.zeros(n, dtype=bool)
        for i in range(n):
            if dominated[i]:
                continue
            # point i is dominated by j if for all objectives j <= i and for at least one <
            # Here we assume minimization objectives, as standard for hypervolume in pygmo.
            # If objectives are to be maximized, the user should pass negated objectives.
            for j in range(n):
                if i == j or dominated[j]:
                    continue
                if np.all(pts[j] <= pts[i]) and np.any(pts[j] < pts[i]):
                    dominated[i] = True
                    break
        return ~dominated

    nd_mask = pareto_front_mask(points)
    nd_indices = np.nonzero(nd_mask)[0]
    nd_points = points[nd_indices]

    # If after filtering we have fewer points than k, fall back to original set (or raise)
    if nd_points.shape[0] < k:
        # Not enough nondominated points: use full set (dominated points can still be needed if k>N_nd)
        candidate_indices = np.arange(N)
    else:
        candidate_indices = nd_indices

    # Helper to compute hypervolume of a set of points (expects minimization objectives)
    def compute_hv(pts):
        if pts.size == 0:
            return 0.0
        try:
            hv = pg.hypervolume(pts)
            return float(hv.compute(reference_point))
        except Exception as e:
            # propagate a helpful message
            raise RuntimeError(f"Hypervolume computation failed: {e}") from e

    # Greedy selection: start with empty set and add the point with largest marginal HV gain each step
    selected_indices = []
    selected_mask = np.zeros(N, dtype=bool)

    current_hv = 0.0
    # For speed, maintain a list of candidate indices to consider
    remaining = list(candidate_indices)

    rng = np.random.default_rng()

    for _ in range(k):
        best_idx = None
        best_gain = -np.inf
        best_ties = []

        # compute candidate gains
        for idx in remaining:
            if selected_mask[idx]:
                continue
            if not selected_indices:
                # marginal hv is simply hv({pt})
                new_hv = compute_hv(points[[idx]])
            else:
                new_selected_pts = np.vstack([points[selected_indices], points[idx]])
                new_hv = compute_hv(new_selected_pts)

            gain = new_hv - current_hv
            # numeric tolerance for tie-handling
            if gain > best_gain + 1e-12:
                best_gain = gain
                best_ties = [idx]
            elif abs(gain - best_gain) <= 1e-12:
                best_ties.append(idx)

        if not best_ties:
            # Should not happen unless numerical issues; pick a random remaining
            choices = [idx for idx in remaining if not selected_mask[idx]]
            if not choices:
                break
            chosen = rng.choice(choices)
        else:
            # tie-break uniformly at random among best
            chosen = rng.choice(best_ties)

        # Add chosen to selection
        selected_indices.append(chosen)
        selected_mask[chosen] = True

        # Update current_hv
        if len(selected_indices) == 1:
            current_hv = compute_hv(points[selected_indices])
        else:
            current_hv = compute_hv(points[selected_indices])

        # If we used nd filtering and still have more candidates than needed, we can remove chosen from remaining
        if chosen in remaining:
            remaining.remove(chosen)

        # If remaining becomes empty but we still need points (possible when nd_points < k), refill remaining
        if not remaining and len(selected_indices) < k:
            remaining = [i for i in range(N) if not selected_mask[i]]

    # If we selected fewer than k (unlikely), fill up with arbitrary remaining points
    if len(selected_indices) < k:
        for idx in range(N):
            if not selected_mask[idx]:
                selected_indices.append(idx)
                selected_mask[idx] = True
            if len(selected_indices) == k:
                break

    subset = points[selected_indices]
    # Ensure returned shape is (k, D)
    if subset.shape[0] != k:
        # If something went wrong, raise
        raise RuntimeError(f"Selected {subset.shape[0]} points, expected {k}.")

    return np.asarray(subset)

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. "
                          "Please install pygmo (e.g. pip install pygmo) or provide it in the environment.") from e

    points = np.asarray(points, dtype=float)
    if points.ndim == 1:
        points = points.reshape(1, -1)
    N, D = points.shape

    # trivial cases
    if N == 0 or k <= 0:
        return np.empty((0, D))

    # reference point
    if reference_point is None:
        ref = np.max(points, axis=0) * 1.1
    else:
        ref = np.asarray(reference_point, dtype=float).ravel()
        if ref.size != D:
            raise ValueError("reference_point must have the same dimensionality as points")

    # If k >= N: return all points; if k > N, pad with random duplicates to reach k
    if k >= N:
        if k == N:
            return points.copy()
        else:
            rng = np.random.default_rng(2025)
            extra = k - N
            idx_extra = rng.choice(N, size=extra, replace=True)
            return np.vstack([points.copy(), points[idx_extra]])

    # Precompute simple individual upper-bound hypervolumes (box to reference)
    diffs = np.maximum(ref.reshape(1, -1) - points, 0.0)
    indiv_hv = np.prod(diffs, axis=1)

    selected = []
    selected_set = set()
    current_points = np.empty((0, D), dtype=float)
    current_hv = 0.0

    # Full greedy: at each iteration, compute exact marginal gain for every unselected candidate
    for it in range(k):
        best_idx = None
        best_gain = -np.inf

        # If current set is empty, we can use precomputed individual HVs (exact for singletons)
        if current_points.shape[0] == 0:
            # choose the unselected point with max individual hv
            unselected = [i for i in range(N) if i not in selected_set]
            # if all indiv_hv are zero (or negative due to numerical issues), we still pick the max
            best_idx = int(max(unselected, key=lambda i: indiv_hv[i]))
            best_gain = float(indiv_hv[best_idx])
        else:
            # compute true marginal gains for every unselected candidate
            for j in range(N):
                if j in selected_set:
                    continue
                # build temporary array with candidate added
                try:
                    arr = np.vstack([current_points, points[j].reshape(1, -1)])
                    hv_with = float(pg.hypervolume(arr).compute(ref))
                    gain = hv_with - current_hv
                except Exception:
                    # fallback to conservative estimate (individual hv) if hypervolume fails
                    gain = float(indiv_hv[j])
                    hv_with = current_hv + gain

                # guard tiny negatives
                if gain < 0 and gain > -1e-12:
                    gain = 0.0

                if gain > best_gain:
                    best_gain = gain
                    best_idx = int(j)

        # If no positive gain found (or all candidates exhausted), pick remaining with largest individual hv
        if best_idx is None or (best_gain <= 0 and len(selected) < k):
            # pick highest individual hv among unselected
            unselected = [i for i in range(N) if i not in selected_set]
            if not unselected:
                break
            best_idx = int(max(unselected, key=lambda i: indiv_hv[i]))
            try:
                if current_points.shape[0] == 0:
                    hv_with = float(pg.hypervolume(points[best_idx].reshape(1, -1)).compute(ref))
                else:
                    arr = np.vstack([current_points, points[best_idx].reshape(1, -1)])
                    hv_with = float(pg.hypervolume(arr).compute(ref))
                best_gain = hv_with - current_hv
            except Exception:
                best_gain = float(indiv_hv[best_idx])
                hv_with = current_hv + best_gain

        # Add chosen point
        selected.append(int(best_idx))
        selected_set.add(int(best_idx))
        if current_points.shape[0] == 0:
            current_points = points[best_idx].reshape(1, -1).copy()
        else:
            current_points = np.vstack([current_points, points[best_idx].reshape(1, -1)])
        # update current_hv using reliable computation
        try:
            current_hv = float(pg.hypervolume(current_points).compute(ref))
        except Exception:
            # as fallback, increment by best_gain if available
            current_hv = current_hv + (best_gain if best_gain is not None else 0.0)

    # Safety: if still short, fill by highest individual hv
    if len(selected) < k:
        unselected = [i for i in range(N) if i not in selected_set]
        unselected_sorted = sorted(unselected, key=lambda i: indiv_hv[i], reverse=True)
        for idx in unselected_sorted:
            if len(selected) >= k:
                break
            selected.append(int(idx))
            selected_set.add(int(idx))

    # Final safety random pad if still short
    if len(selected) < k:
        rng = np.random.default_rng(2025)
        unselected = [i for i in range(N) if i not in selected_set]
        need = k - len(selected)
        if len(unselected) == 0:
            idx_extra = rng.choice(N, size=need, replace=True)
            selected.extend([int(i) for i in idx_extra])
        else:
            picks = rng.choice(unselected, size=min(need, len(unselected)), replace=False)
            selected.extend([int(i) for i in picks])
            if len(selected) < k:
                extra = rng.choice(N, size=k - len(selected), replace=True)
                selected.extend([int(i) for i in extra])

    selected = selected[:k]
    return points[np.array(selected, dtype=int)].copy()
